using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummaryService summaryService) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summaryService.Summarize(request.DocumentText, request.MaxSentences);

        var originalWordCount = request.DocumentText.Split(
            (char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
        var summaryWordCount = summary.Split(
            (char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWordCount,
            SummaryWordCount = summaryWordCount
        });
    }
}

